use postgres::Client;

pub async fn find_user_by_email(email: &str) -> Vec<User> {
    let mut client = Client::connect("postgres://user:password@host:port/database").await.unwrap();

    let query = format!("SELECT * FROM users WHERE email = $1", email);
    let results = client.query(&query, &[&email]).await.unwrap();

    results
        .iter()
        .map(|row| User {
            id: row.get(0),
            email: row.get(1),
            name: row.get(2),
        })
        .collect()
}

